			g_R_S_im = Internal.ReadFromProperty(s_g_R_S_im, NWORDS64_FIELD);
			g_phiR_phiS_re = Internal.ReadFromProperty(s_g_phiR_phiS_re, NWORDS64_FIELD);
			g_phiR_phiS_im = Internal.ReadFromProperty(s_g_phiR_phiS_im, NWORDS64_FIELD);
			Montgomery_RB1 = Internal.ReadFromProperty(s_Montgomery_RB1, NWORDS64_FIELD);
			Montgomery_RB2 = Internal.ReadFromProperty(s_Montgomery_RB2, NWORDS64_FIELD);
			threeinv = Internal.ReadFromProperty(s_threeinv, NWORDS64_FIELD);
			u_entang = Internal.ReadFromProperty(s_u_entang, 2 * NWORDS64_FIELD);
			u0_entang = Internal.ReadFromProperty(s_u0_entang, 2 * NWORDS64_FIELD);
			table_r_qr = Internal.ReadFromProperty(s_table_r_qr, TABLE_R_LEN, NWORDS64_FIELD);
			table_r_qnr = Internal.ReadFromProperty(s_table_r_qnr, TABLE_R_LEN, NWORDS64_FIELD);
			table_v_qr = Internal.ReadFromProperty(s_table_v_qr, TABLE_V_LEN, NWORDS64_FIELD);
			table_v_qnr = Internal.ReadFromProperty(s_table_v_qnr, TABLE_V_LEN, NWORDS64_FIELD);
			v_3_torsion = Internal.ReadFromProperty(s_v_3_torsion, TABLE_V3_LEN, 2u, NWORDS64_FIELD);
			T_tate3 = Internal.ReadFromProperty(s_T_tate3, (6 * (OBOB_EXPON - 1) + 4) * NWORDS64_FIELD);
			T_tate2_firststep_P = Internal.ReadFromProperty(s_T_tate2_firststep_P, 4 * NWORDS64_FIELD);
			T_tate2_P = Internal.ReadFromProperty(s_T_tate2_P, 3 * (OALICE_BITS - 2) * NWORDS64_FIELD);
			T_tate2_firststep_Q = Internal.ReadFromProperty(s_T_tate2_firststep_Q, 4 * NWORDS64_FIELD);
			T_tate2_Q = Internal.ReadFromProperty(s_T_tate2_Q, 3 * (OALICE_BITS - 2) * NWORDS64_FIELD);
			ph2_T = Internal.ReadFromProperty(s_ph2_T, DLEN_2 * (ELL2_W >> 1) * 2 * NWORDS64_FIELD);
			ph3_T1 = Internal.ReadFromProperty(s_ph3_T1, DLEN_3 * (ELL3_W >> 1) * 2 * NWORDS64_FIELD);
			ph3_T2 = Internal.ReadFromProperty(s_ph3_T2, DLEN_3 * (ELL3_W >> 1) * 2 * NWORDS64_FIELD);
			ph2_T1 = new ulong[2 * ((DLEN_2 - 1) * (ELL2_W / 2) + (ph2_path[PLEN_2 - 1] - 1))];
			ph2_T2 = new ulong[2 * ((DLEN_2 - 1) * (ELL2_W / 2) + (ph2_path[PLEN_2 - 1] - 1))];
			ph3_T = new ulong[2 * ((DLEN_3 - 1) * (ELL3_W / 2) + (ph3_path[PLEN_3 - 1] - 1))];
		}
	}
